def fetch_site_ids(user, opts \\ []) do
  team = Keyword.get(opts, :team)

  Repo.all(
    from(u in subquery(Sites.accessible_by(user, team)),
      inner_join: s in ^Site.regular(),
      on: u.site_id == s.id,
      select: s.id
    )
  )
end

