def decode_ber_length(<<1::integer-1, length_bytes::big-integer-7, rest::binary>>) do
  length_bits = length_bytes * 8

  case rest do
    <<length::unsigned-big-integer-size(length_bits), rest::binary>> -> {:ok, length, rest}
    _ -> {:error, :wrong_length}
  end
end
def decode_ber_length(<<length::unsigned-integer-big-8, rest::binary>>) do
  {:ok, length, rest}
end
def decode_ber_length(_) do
  {:error, :wrong_length}
end

def decode(binary) when is_binary(binary) do
  case :binary.split(binary, @suffix) do
    [line, rest] -> {:ok, String.trim_trailing(line, "\r"), rest}
    [_] -> {:error, :too_short}
  end
end

